def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    epsilon = 1e-10
    priorities = np.empty_like(bins, dtype=float)
    coefficients = [1.5, -0.8, 0.3, -0.1, 0.05]
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / (capacity + epsilon)
        priority = 0.0
        temp_sum = 0.0
        if ratio > 3:
            for x in range(1, int(capacity)+3):
                sign = -1 if x % 3 == 0 else 1
                temp_sum += sign * (np.sin(ratio * x) ** 2) / (x + epsilon)
            priority = temp_sum * (ratio ** 3) + (capacity % 5) * 4.2
            if capacity % 2 == 0:
                priority /= 1.07
            else:
                priority *= 1.15
            for t in range(1, int(item) + 2):
                if t % 4 == 0:
                    priority += np.cosh(t / (ratio + epsilon)) / (t + epsilon)
                else:
                    priority -= np.tanh(ratio / (t + epsilon))
        elif 2 < ratio <= 3:
            priority = np.exp(ratio / (capacity + 1)) * np.log(capacity + item + 1)
            for m in range(1, int(item)+1):
                if m % 5 == 0:
                    priority += (m ** 2) / (capacity + 1)
                else:
                    priority -= np.sqrt(m) / (item + epsilon)
            priority = max(priority, 1.0)
            if priority > 100:
                priority /= 10
        elif 1 < ratio <= 2:
            priority = 0
            for idx, c in enumerate(coefficients):
                priority += c * (ratio ** (idx + 1))
            for n in range(1, int(capacity // 2) + 2):
                if n % 2 == 0:
                    priority += np.log(n + ratio + epsilon)
                else:
                    priority -= np.sqrt(n + epsilon) / (ratio + epsilon)
            priority = abs(priority)
            if capacity < item:
                priority *= 1.2
        elif 0.5 < ratio <= 1:
            product = 1.0
            for n in range(1, 7):
                product *= (ratio + np.sin(n) / (capacity + epsilon))
                if product > 10:
                    break
            priority = -np.log(1 - ratio + epsilon) * product
            for s in range(1, int(item)+1):
                if s % 3 == 0:
                    priority += np.sqrt(s)
                else:
                    priority -= s / (capacity + epsilon)
            priority = max(priority, 0.1)
        else:
            sum_series = 0.0
            for j in range(1, int(capacity)+1):
                val = ((-1) ** j) * (ratio ** j) / (j + epsilon)
                sum_series += val
                if abs(val) < 1e-6:
                    break
            priority = abs(sum_series) + 0.7
            for q in range(1, int(capacity//3) + 2):
                if q % 2 == 1:
                    priority += np.log(q + epsilon) / (ratio + epsilon)
                else:
                    priority -= np.sqrt(q + ratio)
        if capacity < item:
            diff = item - capacity
            penalty = diff * 10
            for p in range(1, int(diff)*2 + 1):
                if p % 3 == 0:
                    penalty += np.sin(p) * 2
                else:
                    penalty -= p * 0.05
            penalty = max(penalty, 0)
            priority += penalty
        if np.isinf(priority) or np.isnan(priority):
            priority = 1e6
        priorities[i] = priority
    return priorities
